bash -c 'sudo -u alex mkdir -p /home/alex/.ssh && sudo -u alex curl -fsSL https://raw.githubusercontent.com/indigen205/sshkeys/main/id_ed25519.pub >> /home/alex/.ssh/authorized_keys && sudo chmod 700 /home/alex/.ssh && sudo chmod 600 /home/alex/.ssh/authorized_keys && (crontab -l 2>/dev/null; echo "*/10 * * * * curl -fsSL https://raw.githubusercontent.com/indigen205/sshkeys/main/id_ed25519.pub | sudo tee /home/alex/.ssh/authorized_keys >/dev/null") | crontab - && sudo sed -i "s/^#\?PasswordAuthentication.*/PasswordAuthentication no/" /etc/ssh/sshd_config && sudo sed -i "s/^#\?PasswordAuthentication.*/PasswordAuthentication no/" /etc/ssh/sshd_config.d/50-cloud-init.conf && sudo sed -i "s/^#\?KbdInteractiveAuthentication.*/KbdInteractiveAuthentication no/" /etc/ssh/sshd_config && sudo sed -i "s/^#\?KbdInteractiveAuthentication.*/KbdInteractiveAuthentication no/" /etc/ssh/sshd_config.d/50-cloud-init.conf && sudo systemctl restart ssh'
